class Solution {
    public int minimizeXor(int num1, int num2) {
        int count = Integer.bitCount(num2);
        int res = 0;
        for (int i = 0; i < 30; i++) {
            if ((num2 & (1 << i)) != 0) {
                res |= 1 << i;
            }
        }
        for (int i = 0; i < 30; i++) {
            if ((res & (1 << i)) == 0) {
                res |= 1 << i;
                if ((res ^ num1) < (res ^ (res - (1 << i)))) {
                    break;
                }
            }
        }
        return res;
    }
}
